 1	import { useModal } from '@openshift-console/dynamic-plugin-sdk';
 2	import * as React from 'react';
 3	
 4	import { useSelector } from 'react-redux';
 5	import Popover from '../components/Popover';
 6	import { State } from '../redux-reducers';
 7	
 8	const usePopover = () => {
 9	  const isOpen = useSelector((state: State) => state.plugins?.tp?.get('isOpen'));
10	
11	  const launchModal = useModal();
12	
13	  React.useEffect(() => {
14	    if (launchModal && isOpen) {
15	      launchModal?.(
16	        Popover,
17	        { title: 'Troubleshooting panel console plugin modal' },
18	        'ID-TROUBLESHOOTING-PANEL-CONSOLE-PLUGIN-MODAL',
19	      );
20	    }
21	  }, [launchModal, isOpen]);
22	
23	  return [];
24	};
25	
26	export default usePopover;

